                  >
                    Load
                  </button>
                  <button
                    onClick={() => exportPreset(preset)}
                    className="px-3 py-1.5 bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-buttontext-sm font-medium"
                  >
                    Export
                  </button>
                  {!preset.isDefault && (
                    <button
                      onClick={() => deletePreset(preset.id)}
                      className="px-3 py-1.5 bg-red-600 hover:bg-red-700 text-white rounded-buttontext-sm font-medium"
