import React, { useState, useEffect } from 'react';
import { useWidgetStore } from '../stores/useWidgetStore';

export interface WidgetPreset {
  id: string;
  name: string;
  description?: string;
  enabledWidgets: string[];
  widgetSizes: Record<string, 1 | 2 | 3>;
  createdAt: string;
  isDefault?: boolean;
}

// Default preset layouts
const DEFAULT_PRESETS: WidgetPreset[] = [
  {
    id: 'default',
    name: 'Default',
    description: 'Core widgets: Weather, Tasks Summary, Quick Add, Events & Notes',
    enabledWidgets: ['weathermap', 'taskssummary', 'tasksquickadd', 'upcomingevents', 'recentnotes'],
    widgetSizes: {
      weathermap: 3,
      taskssummary: 1,
      tasksquickadd: 1,
      upcomingevents: 1,
      recentnotes: 1,
    },
    createdAt: new Date().toISOString(),
    isDefault: true,
  },
  {
    id: 'productivity',
    name: 'Productivity Focus',
    description: 'Task-focused layout for getting work done',
    enabledWidgets: ['weathermap', 'tasksquickadd', 'upcomingevents', 'recentnotes', 'pomodoro'],
    widgetSizes: {
      weathermap: 3,
      tasksquickadd: 3,
      upcomingevents: 1,
      recentnotes: 1,
      pomodoro: 1,
    },
    createdAt: new Date().toISOString(),
    isDefault: true,
  },
  {
    id: 'developer',
    name: 'Developer Dashboard',
    description: 'GitHub, Hacker News, and dev tools',
    enabledWidgets: ['weathermap', 'github', 'hackernews', 'recentnotes', 'shortcuts', 'calculator'],
    widgetSizes: {
      weathermap: 3,
      github: 2,
      hackernews: 2,
      recentnotes: 1,
      shortcuts: 1,
      calculator: 1,
    },
    createdAt: new Date().toISOString(),
    isDefault: true,
  },
  {
    id: 'minimal',
    name: 'Minimal',
    description: 'Just the essentials',
    enabledWidgets: ['weathermap', 'tasksquickadd'],
    widgetSizes: {
      weathermap: 3,
      tasksquickadd: 3,
    },
    createdAt: new Date().toISOString(),
    isDefault: true,
  },
];

interface PresetManagerProps {
  isOpen: boolean;
  onClose: () => void;
}

/**
 * Preset Manager Component
 *
 * Allows users to:
 * - Save current layout as named preset
 * - Load saved presets
 * - Delete custom presets
 * - Use default presets
 * - Export/import presets as JSON
 */
export const PresetManager: React.FC<PresetManagerProps> = ({ isOpen, onClose }) => {
  const [presets, setPresets] = useState<WidgetPreset[]>([]);
  const [showSaveDialog, setShowSaveDialog] = useState(false);
  const [presetName, setPresetName] = useState('');
  const [presetDescription, setPresetDescription] = useState('');

  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);
  const setWidgetSize = useWidgetStore((state) => state.setWidgetSize);
  const enableWidget = useWidgetStore((state) => state.enableWidget);
  const disableWidget = useWidgetStore((state) => state.disableWidget);

  // Load presets from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('dashboard-presets');
    if (saved) {
      try {
        const customPresets = JSON.parse(saved) as WidgetPreset[];
        setPresets([...DEFAULT_PRESETS, ...customPresets]);
      } catch (error) {
        console.error('Failed to load presets:', error);
        setPresets(DEFAULT_PRESETS);
      }
    } else {
      setPresets(DEFAULT_PRESETS);
    }
  }, []);

  const savePreset = () => {
    if (!presetName.trim()) return;

    const newPreset: WidgetPreset = {
      id: Date.now().toString(),
      name: presetName,
      description: presetDescription || undefined,
      enabledWidgets: [...enabledWidgets],
      widgetSizes: { ...widgetSizes },
      createdAt: new Date().toISOString(),
      isDefault: false,
    };

    const customPresets = presets.filter((p) => !p.isDefault);
    const updatedCustom = [...customPresets, newPreset];
    localStorage.setItem('dashboard-presets', JSON.stringify(updatedCustom));

    setPresets([...DEFAULT_PRESETS, ...updatedCustom]);
    setShowSaveDialog(false);
    setPresetName('');
    setPresetDescription('');
  };

  const loadPreset = (preset: WidgetPreset) => {
    // Disable all current widgets
    enabledWidgets.forEach((widgetId) => {
      disableWidget(widgetId);
    });

    // Enable preset widgets in order
    preset.enabledWidgets.forEach((widgetId) => {
      enableWidget(widgetId);
    });

    // Set widget sizes
    Object.entries(preset.widgetSizes).forEach(([widgetId, size]) => {
      setWidgetSize(widgetId, size);
    });

    // Reorder to match preset
    reorderWidgets(preset.enabledWidgets);

    onClose();
  };

  const deletePreset = (presetId: string) => {
    const customPresets = presets.filter((p) => !p.isDefault && p.id !== presetId);
    localStorage.setItem('dashboard-presets', JSON.stringify(customPresets));
    setPresets([...DEFAULT_PRESETS, ...customPresets]);
  };

  const exportPreset = (preset: WidgetPreset) => {
    const json = JSON.stringify(preset, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${preset.name.replace(/\s+/g, '-').toLowerCase()}-preset.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importPreset = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const text = await file.text();
      const preset = JSON.parse(text) as WidgetPreset;

      // Validate preset structure
      if (!preset.name || !preset.enabledWidgets || !preset.widgetSizes) {
        alert('Invalid preset file format');
        return;
      }

      // Generate new ID and timestamp
      preset.id = Date.now().toString();
      preset.createdAt = new Date().toISOString();
      preset.isDefault = false;

      const customPresets = presets.filter((p) => !p.isDefault);
      const updatedCustom = [...customPresets, preset];
      localStorage.setItem('dashboard-presets', JSON.stringify(updatedCustom));
      setPresets([...DEFAULT_PRESETS, ...updatedCustom]);
    } catch (error) {
      console.error('Failed to import preset:', error);
      alert('Failed to import preset. Please check the file format.');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-surface-light dark:bg-surface-dark rounded-button shadow-2xl w-full max-w-2xl max-h-[80vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-border-light dark:border-border-dark">
          <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            Layout Presets
          </h2>
          <button
            onClick={onClose}
            className="text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary"
            aria-label="Close preset manager"
          >
            ✕
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Save Current Layout Button */}
          <div className="mb-6">
            <button
              onClick={() => setShowSaveDialog(true)}
              className="w-full px-4 py-3 bg-accent-blue dark:bg-accent-cyan hover:bg-accent-blue-hover dark:hover:bg-accent-cyan-hover text-white rounded-button font-medium transition-all duration-standard ease-smooth"
            >
              💾 Save Current Layout
            </button>
          </div>

          {/* Save Dialog */}
          {showSaveDialog && (
            <div className="mb-6 p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button border border-border-light dark:border-border-dark">
              <h3 className="text-lg font-medium text-text-light-primary dark:text-text-dark-primary mb-3">
                Save Current Layout
              </h3>
              <input
                type="text"
                value={presetName}
                onChange={(e) => setPresetName(e.target.value)}
                placeholder="Preset name (e.g., My Workflow)"
                className="w-full px-3 py-2 mb-3 bg-white dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-buttontext-text-light-primary dark:text-text-dark-primary"
              />
              <textarea
                value={presetDescription}
                onChange={(e) => setPresetDescription(e.target.value)}
                placeholder="Description (optional)"
                rows={2}
                className="w-full px-3 py-2 mb-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button text-text-light-primary dark:text-text-dark-primary"
              />
              <div className="flex gap-2">
                <button
                  onClick={savePreset}
                  disabled={!presetName.trim()}
                  className="px-4 py-2 bg-accent-blue dark:bg-accent-cyan hover:bg-accent-blue-hover dark:hover:bg-accent-cyan-hover text-white rounded-button font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Save
                </button>
                <button
                  onClick={() => {
                    setShowSaveDialog(false);
                    setPresetName('');
                    setPresetDescription('');
                  }}
                  className="px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium"
                >
                  Cancel
                </button>
              </div>
            </div>
          )}

          {/* Import Preset Button */}
          <div className="mb-6">
            <label className="block w-full px-4 py-3 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium transition-all duration-standard ease-smooth cursor-pointer text-center">
              📥 Import Preset
              <input
                type="file"
                accept=".json"
                onChange={importPreset}
                className="hidden"
              />
            </label>
          </div>

          {/* Preset List */}
          <div className="space-y-3">
            <h3 className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary uppercase">
              Available Presets
            </h3>
            {presets.map((preset) => (
              <div
                key={preset.id}
                className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button border border-border-light dark:border-border-dark"
              >
                <div className="flex items-start justify-between mb-2">
                  <div className="flex-1">
                    <h4 className="text-base font-medium text-text-light-primary dark:text-text-dark-primary">
                      {preset.name}
                      {preset.isDefault && (
                        <span className="ml-2 text-xs px-2 py-0.5 bg-accent-blue/20 dark:bg-accent-cyan/20 text-accent-blue dark:text-accent-cyan rounded">
                          Default
                        </span>
                      )}
                    </h4>
                    {preset.description && (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
                        {preset.description}
                      </p>
                    )}
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                      {preset.enabledWidgets.length} widgets
                    </p>
                  </div>
                </div>
                <div className="flex gap-2 mt-3">
                  <button
                    onClick={() => loadPreset(preset)}
                    className="px-3 py-1.5 bg-accent-blue dark:bg-accent-cyan hover:bg-accent-blue-hover dark:hover:bg-accent-cyan-hover text-white rounded-button text-sm font-medium"
                  >
                    Load
                  </button>
                  <button
                    onClick={() => exportPreset(preset)}
                    className="px-3 py-1.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-button text-sm font-medium"
                  >
                    Export
                  </button>
                  {!preset.isDefault && (
                    <button
                      onClick={() => deletePreset(preset.id)}
                      className="px-3 py-1.5 bg-accent-red hover:bg-accent-red-hover text-white rounded-button text-sm font-medium"
                    >
                      Delete
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * Widget Manager Modal
 *
 * Allows users to enable/disable/reorder dashboard widgets with category organization
 */

import React, { useState, useRef, useEffect } from 'react';
import { Modal } from './Modal';
import { useWidgetStore } from '../stores/useWidgetStore';
import { getAllWidgets, getWidget, type WidgetCategory } from '../widgets/Dashboard/WidgetRegistry';
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import type { DragEndEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

interface WidgetManagerProps {
  isOpen: boolean;
  onClose: () => void;
}

interface SettingsPromptData {
  widgetId: string;
  widgetName: string;
}

const SortableItem: React.FC<{ id: string }> = ({ id }) => {
  const { attributes, listeners, setNodeRef, transform, transition } = useSortable({ id });
  const widget = getWidget(id);

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  if (!widget) return null;

  return (
    <div
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...listeners}
      className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark rounded-button cursor-move hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
    >
      <span className="text-2xl">{widget.icon}</span>
      <div className="flex-1">
        <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary">
          {widget.name}
        </h4>
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          {widget.description}
        </p>
      </div>
      <span className="text-text-light-secondary dark:text-text-dark-secondary">⋮⋮</span>
    </div>
  );
};

export const WidgetManager: React.FC<WidgetManagerProps> = ({ isOpen, onClose }) => {
  const { enabledWidgets, enableWidget, disableWidget, reorderWidgets, updateWidgetSettings } = useWidgetStore();
  const [activeTab, setActiveTab] = useState<'enabled' | 'available'>('enabled');
  const [settingsPrompt, setSettingsPrompt] = useState<SettingsPromptData | null>(null);
  const [githubUsername, setGithubUsername] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<WidgetCategory | 'all'>('all');
  const [selectedIndex, setSelectedIndex] = useState<number>(0);
  const searchInputRef = useRef<HTMLInputElement>(null);

  const allWidgets = getAllWidgets();
  const availableWidgets = allWidgets.filter(w => !enabledWidgets.includes(w.id));

  // Filter available widgets by search and category
  const filteredAvailableWidgets = availableWidgets.filter(widget => {
    const matchesSearch = !searchQuery ||
      widget.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      widget.description.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesCategory = selectedCategory === 'all' || widget.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });

  // Category display names
  const categoryNames: Record<WidgetCategory, string> = {
    core: '⭐ Core Features',
    productivity: '💼 Productivity',
    news: '📰 News & Info',
    finance: '💰 Finance',
    visual: '🎨 Visual',
    dev: '🔧 Developer Tools',
    fun: '🎮 Fun & Games',
    utility: '🛠️ Utilities',
  };

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { distance: 8 },
    })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const oldIndex = enabledWidgets.indexOf(active.id as string);
    const newIndex = enabledWidgets.indexOf(over.id as string);

    const newOrder = [...enabledWidgets];
    const [moved] = newOrder.splice(oldIndex, 1);
    newOrder.splice(newIndex, 0, moved);
    reorderWidgets(newOrder);
  };

  const handleEnableWidget = (widgetId: string) => {
    const widget = getWidget(widgetId);
    if (!widget) return;

    // Check if widget requires settings (like GitHub username)
    if (widget.requiresAuth && widgetId === 'github') {
      setSettingsPrompt({ widgetId, widgetName: widget.name });
    } else {
      enableWidget(widgetId);
    }
  };

  const handleSaveSettings = () => {
    if (!settingsPrompt) return;

    if (settingsPrompt.widgetId === 'github') {
      if (!githubUsername.trim()) {
        alert('Please enter at least one GitHub username');
        return;
      }

      // Support comma-separated usernames for multiple widgets
      const usernames = githubUsername.split(',').map(u => u.trim()).filter(u => u);

      if (usernames.length === 0) {
        alert('Please enter valid GitHub username(s)');
        return;
      }

      // Enable multiple GitHub widgets if multiple usernames provided
      usernames.forEach((username, index) => {
        const widgetId = index === 0 ? 'github' : `github-${index}`;
        updateWidgetSettings(widgetId, { username });
        enableWidget(widgetId);
      });

      setSettingsPrompt(null);
      setGithubUsername('');
    }
  };

  const handleCancelSettings = () => {
    setSettingsPrompt(null);
    setGithubUsername('');
  };

  // Auto-focus search when tab changes to "available"
  useEffect(() => {
    if (activeTab === 'available' && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [activeTab]);

  // Reset selected index when search query or category changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [searchQuery, selectedCategory]);

  // Keyboard navigation handler
  const handleKeyDown = (e: React.KeyboardEvent) => {
    const maxIndex = filteredAvailableWidgets.length - 1;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(prev => Math.min(prev + 1, maxIndex));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(prev => Math.max(prev - 1, 0));
        break;
      case 'Enter':
        e.preventDefault();
        if (filteredAvailableWidgets[selectedIndex]) {
          handleEnableWidget(filteredAvailableWidgets[selectedIndex].id);
          setSearchQuery(''); // Clear search after adding
          setSelectedIndex(0);
        }
        break;
      case 'Escape':
        e.preventDefault();
        setSearchQuery('');
        setSelectedIndex(0);
        searchInputRef.current?.focus();
        break;
    }
  };

  // Text highlighting helper
  const highlightText = (text: string, query: string): React.ReactNode => {
    if (!query.trim()) return text;

    // Escape special regex characters
    const escapedQuery = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`(${escapedQuery})`, 'gi');
    const parts = text.split(regex);

    return parts.map((part, i) =>
      regex.test(part) ? (
        <mark key={i} className="bg-accent-yellow/30 dark:bg-accent-yellow/50 font-semibold">
          {part}
        </mark>
      ) : (
        part
      )
    );
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Customize Dashboard Widgets" maxWidth="2xl">
      <div className="w-full">
        {/* Tabs */}
        <div className="flex gap-2 mb-4 border-b border-border-light dark:border-border-dark">
          <button
            onClick={() => setActiveTab('enabled')}
            className={`px-4 py-2 font-medium transition-all duration-standard ease-smooth ${
              activeTab === 'enabled'
                ? 'text-accent-blue border-b-2 border-accent-blue'
                : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            Active Widgets ({enabledWidgets.length})
          </button>
          <button
            onClick={() => setActiveTab('available')}
            className={`px-4 py-2 font-medium transition-all duration-standard ease-smooth ${
              activeTab === 'available'
                ? 'text-accent-blue border-b-2 border-accent-blue'
                : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            Available ({availableWidgets.length})
          </button>
        </div>

        {/* Content */}
        <div className="min-h-[300px]">
          {activeTab === 'enabled' ? (
            <div className="space-y-4">
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Drag to reorder widgets. Click to disable.
              </p>

              <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={enabledWidgets} strategy={verticalListSortingStrategy}>
                  <div className="space-y-2">
                    {enabledWidgets.map((id) => {
                      const widget = getWidget(id);
                      if (!widget) return null;

                      return (
                        <div key={id} className="flex items-center gap-2">
                          <div className="flex-1">
                            <SortableItem id={id} />
                          </div>
                          <button
                            onClick={() => disableWidget(id)}
                            className="p-2 text-accent-red hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded-button transition-all duration-standard ease-smooth"
                            title="Disable widget"
                          >
                            ✕
                          </button>
                        </div>
                      );
                    })}
                  </div>
                </SortableContext>
              </DndContext>

              {enabledWidgets.length === 0 && (
                <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                  No widgets enabled. Add some from the Available tab!
                </div>
              )}
            </div>
          ) : (
            <div className="space-y-4">
              {/* Search Bar */}
              <input
                ref={searchInputRef}
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Search widgets... (↑↓ arrows, Enter to add, ESC to clear)"
                className="w-full px-4 py-2 rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue focus:border-transparent transition-all duration-standard ease-smooth"
              />

              {/* Category Tabs */}
              <div className="flex gap-2 flex-wrap">
                <button
                  onClick={() => setSelectedCategory('all')}
                  className={`px-3 py-1.5 rounded-button text-sm font-medium transition-all duration-standard ease-smooth ${
                    selectedCategory === 'all'
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                  }`}
                >
                  All ({availableWidgets.length})
                </button>
                {Object.entries(categoryNames).map(([category, displayName]) => {
                  const count = availableWidgets.filter(w => w.category === category).length;
                  if (count === 0) return null;

                  return (
                    <button
                      key={category}
                      onClick={() => setSelectedCategory(category as WidgetCategory)}
                      className={`px-3 py-1.5 rounded-button text-sm font-medium transition-all duration-standard ease-smooth ${
                        selectedCategory === category
                          ? 'bg-accent-blue text-white'
                          : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                      }`}
                    >
                      {displayName.split(' ')[0]} ({count})
                    </button>
                  );
                })}
              </div>

              {/* Widget Grid */}
              {availableWidgets.length === 0 ? (
                <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                  All widgets are already enabled!
                </div>
              ) : filteredAvailableWidgets.length === 0 ? (
                <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                  No widgets found matching your search.
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3">
                  {filteredAvailableWidgets.map((widget, index) => (
                    <button
                      key={widget.id}
                      onClick={() => handleEnableWidget(widget.id)}
                      className={`flex flex-col items-start gap-2 p-3 rounded-button transition-all duration-standard ease-smooth text-left group ${
                        index === selectedIndex
                          ? 'bg-accent-blue/10 ring-2 ring-accent-blue scale-105'
                          : 'bg-surface-light-elevated dark:bg-surface-dark hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                      }`}
                    >
                      <div className="flex items-center gap-2 w-full">
                        <span className="text-2xl">{widget.icon}</span>
                        <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary flex-1 truncate">
                          {highlightText(widget.name, searchQuery)}
                        </h4>
                        <span className="text-accent-blue opacity-0 group-hover:opacity-100 transition-opacity">+</span>
                      </div>
                      <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
                        {highlightText(widget.description, searchQuery)}
                      </p>
                    </button>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="mt-6 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-accent-blue text-white rounded-button hover:bg-accent-blue-hover transition-all duration-standard ease-smooth"
          >
            Done
          </button>
        </div>
      </div>

      {/* Settings Prompt Modal (for GitHub username, etc.) */}
      {settingsPrompt && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60]">
          <div className="bg-white dark:bg-surface-dark-elevated rounded-card p-6 max-w-md w-full mx-4 border border-border-light dark:border-border-dark">
            <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
              Configure {settingsPrompt.widgetName}
            </h3>

            {settingsPrompt.widgetId === 'github' && (
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                    GitHub Username
                  </label>
                  <input
                    type="text"
                    value={githubUsername}
                    onChange={(e) => setGithubUsername(e.target.value)}
                    placeholder="octocat, username2, username3"
                    className="w-full px-3 py-2 border rounded-button bg-white dark:bg-surface-dark border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:border-transparent transition-all duration-standard ease-smooth"
                    autoFocus
                  />
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                    Enter GitHub username(s). Use commas to add multiple widgets (e.g., "username1, username2")
                  </p>
                </div>

                <div className="flex gap-3 justify-end">
                  <button
                    onClick={handleCancelSettings}
                    className="px-4 py-2 border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth text-text-light-primary dark:text-text-dark-primary"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleSaveSettings}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
                  >
                    Save & Enable
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </Modal>
  );
};

